"use strict";function getStyle(e,t){return window.getComputedStyle?getComputedStyle(e,null)[t]:e.currentStyle[t]}try{getStyle(document.getElementById("toggle-menu"),"display").replace(/\s+|px/gi,"")!="none"?document.getElementById("menus").setAttribute("style","display:none!important"):document.getElementById("menus").setAttribute("style","")}catch{}var clientWidth=document.getElementById("content-inner").clientWidth,paddingLeft=Number(getStyle(document.getElementById("content-inner"),"paddingLeft").replace(/\s+|px/gi,"")),paddingRight=Number(getStyle(document.getElementById("content-inner"),"paddingRight").replace(/\s+|px/gi,"")),width=clientWidth-paddingLeft-paddingRight;try{document.getElementById("top").setAttribute("style","width:"+width.toString()+"px")}catch{}$(document).ready(function(){var e=document.getElementById("content-inner").clientWidth,t=Number(getStyle(document.getElementById("content-inner"),"paddingLeft").replace(/\s+|px/gi,"")),d=Number(getStyle(document.getElementById("content-inner"),"paddingRight").replace(/\s+|px/gi,"")),i=e-t-d;try{document.getElementById("top").setAttribute("style","width:"+i.toString()+"px")}catch{}function r(){var n=document.getElementById("content-inner").clientWidth,c=Number(getStyle(document.getElementById("content-inner"),"paddingLeft").replace(/\s+|px/gi,"")),g=Number(getStyle(document.getElementById("content-inner"),"paddingRight").replace(/\s+|px/gi,"")),l=n-c-g;try{document.getElementById("top").setAttribute("style","width:"+l.toString()+"px")}catch{}}window.addEventListener("resize",r)});
